            System.out.print("Enter a command to execute: ");
            String userInput = reader.readLine();

            // Sanitize user input to only allow alphanumeric characters and spaces
            if (!userInput.matches("[a-zA-Z0-9\\s]+")) {
                System.out.println("Invalid input. Please enter only alphanumeric characters and spaces.");
                return;
            }

            Process process = Runtime.getRuntime().exec("ping " + userInput);

            BufferedReader inputReader = new BufferedReader(new InputStreamReader(process.getInputStream()));
            String inputLine;
            while ((inputLine = inputReader.readLine()) != null) {
                System.out.println(inputLine);
            }
        } catch (IOException e) {
            e.printStackTrace();
        }
